     1→/**
     2→ * My Day Widget
     3→ *
     4→ * Unified view of today's tasks, calendar events, and quick actions
     5→ * Inspired by Asana's "Today" view and Microsoft To Do's "My Day" feature
     6→ *
     7→ * Features:
     8→ * - Today's tasks (due today + in progress)
     9→ * - Today's calendar events
    10→ * - Quick task completion
    11→ * - Navigation to full views
    12→ */
    13→
    14→import React, { useState, useMemo } from 'react';
    15→import { BaseWidget } from './BaseWidget';
    16→import { useKanbanStore } from '../../stores/useKanbanStore';
    17→import { useCalendarStore } from '../../stores/useCalendarStore';
    18→import { useNavigate } from 'react-router-dom';
    19→
    20→export const MyDayWidget: React.FC = () => {
    21→  const { tasks, updateTask } = useKanbanStore();
    22→  const { events } = useCalendarStore();
    23→  const navigate = useNavigate();
    24→  const [showCompleted, setShowCompleted] = useState(false);
    25→
    26→  // Get today's date components
    27→  const today = useMemo(() => {
    28→    const now = new Date();
    29→    return {
    30→      date: now,
    31→      dateString: now.toDateString(),
    32→      // Date key in YYYY-M-D format (matches Calendar Events)
    33→      dateKey: `${now.getFullYear()}-${now.getMonth() + 1}-${now.getDate()}`,
    34→      dayName: now.toLocaleDateString('en-US', { weekday: 'long' }),
    35→      monthDay: now.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
    36→    };
    37→  }, []);
    38→
    39→  // Today's tasks (due today OR in progress/review status)
    40→  const todayTasks = useMemo(() => {
    41→    return tasks.filter((t) => {
    42→      // Include if due today
    43→      if (t.dueDate) {
    44→        const due = new Date(t.dueDate);
    45→        if (due.toDateString() === today.dateString) {
    46→          return true;
    47→        }
    48→      }
    49→      // Include if actively being worked on (but not done)
    50→      if (t.status === 'inprogress' || t.status === 'review') {
    51→        return true;
    52→      }
    53→      return false;
    54→    }).sort((a, b) => {
    55→      // Sort: priority (high first), then by due date, then by creation
    56→      const priorityOrder = { high: 0, medium: 1, low: 2 };
    57→      const aPriority = priorityOrder[a.priority || 'medium'];
    58→      const bPriority = priorityOrder[b.priority || 'medium'];
    59→      if (aPriority !== bPriority) return aPriority - bPriority;
    60→
    61→      // Then by due date
    62→      if (a.dueDate && b.dueDate) {
    63→        return new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime();
    64→      }
    65→      if (a.dueDate) return -1;
    66→      if (b.dueDate) return 1;
    67→
    68→      return 0;
    69→    });
    70→  }, [tasks, today.dateString]);
    71→
    72→  // Split into active and completed
    73→  const activeTasks = todayTasks.filter(t => t.status !== 'done');
    74→  const completedTasks = todayTasks.filter(t => t.status === 'done');
    75→
    76→  // Today's events
    77→  const todayEvents = useMemo(() => {
    78→    const eventList = events[today.dateKey] || [];
    79→    return eventList.sort((a, b) => {
    80→      // Sort by start time
    81→      if (a.startTime && b.startTime) {
    82→        return a.startTime.localeCompare(b.startTime);
    83→      }
    84→      if (a.startTime) return -1;
    85→      if (b.startTime) return 1;
    86→      return 0;
    87→    });
    88→  }, [events, today.dateKey]);
    89→
    90→  // Quick complete task
    91→  const handleCompleteTask = (taskId: string) => {
    92→    updateTask(taskId, { status: 'done' });
    93→  };
    94→
    95→  // Priority badge
    96→  const getPriorityBadge = (priority?: 'low' | 'medium' | 'high') => {
    97→    if (!priority || priority === 'medium') return null;
    98→
    99→    const colors = {
   100→      high: 'bg-status-error-bg text-status-error-text',
   101→      low: 'bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary',
   102→    };
   103→
   104→    const icons = {
   105→      high: '🔴',
   106→      low: '🟢',
   107→    };
   108→
   109→    return (
   110→      <span className={`inline-flex items-center gap-0.5 px-1.5 py-0.5 rounded text-xs font-medium ${colors[priority]}`}>
   111→        {icons[priority]}
   112→      </span>
   113→    );
   114→  };
   115→
   116→  const totalTasks = activeTasks.length;
   117→  const totalEvents = todayEvents.length;
   118→  const hasActivity = totalTasks > 0 || totalEvents > 0;
   119→
   120→  return (
   121→    <BaseWidget
   122→      title="My Day"
   123→      icon="☀️"
   124→      subtitle={`${today.dayName}, ${today.monthDay}`}
   125→    >
   126→      <div className="flex flex-col h-full min-h-[300px]">
   127→        {/* Summary Stats */}
   128→        <div className="flex items-center gap-4 mb-4 pb-3 border-b border-border-light dark:border-border-dark">
   129→          <div className="flex items-center gap-2">
   130→            <span className="text-2xl font-bold text-accent-blue">{totalTasks}</span>
   131→            <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
   132→              {totalTasks === 1 ? 'task' : 'tasks'}
   133→            </span>
   134→          </div>
   135→          <div className="w-px h-6 bg-border-light dark:border-border-dark" />
   136→          <div className="flex items-center gap-2">
   137→            <span className="text-2xl font-bold text-accent-magenta">{totalEvents}</span>
   138→            <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
   139→              {totalEvents === 1 ? 'event' : 'events'}
   140→            </span>
   141→          </div>
   142→        </div>
   143→
   144→        {/* Content Area */}
   145→        {hasActivity ? (
   146→          <div className="flex-1 overflow-y-auto space-y-4 mb-4">
   147→            {/* Active Tasks Section */}
   148→            {activeTasks.length > 0 && (
   149→              <div>
   150→                <h3 className="text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary uppercase tracking-wide mb-2">
   151→                  Tasks
   152→                </h3>
   153→                <div className="space-y-1.5">
   154→                  {activeTasks.map((task) => (
   155→                    <div
   156→                      key={task.id}
   157→                      className="group flex items-start gap-2 p-2 rounded hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-all duration-standard ease-smooth"
   158→                    >
   159→                      {/* Checkbox */}
   160→                      <button
   161→                        onClick={() => handleCompleteTask(task.id)}
   162→                        className="flex-shrink-0 mt-0.5 w-4 h-4 rounded border-2 border-accent-blue hover:bg-accent-blue/10 transition-colors"
   163→                        aria-label="Complete task"
   164→                      />
   165→
   166→                      {/* Task Content */}
   167→                      <div className="flex-1 min-w-0">
   168→                        <div className="flex items-start gap-2">
   169→                          <span className="text-sm text-text-light-primary dark:text-text-dark-primary font-medium">
   170→                            {task.title}
   171→                          </span>
   172→                          {getPriorityBadge(task.priority)}
   173→                        </div>
   174→                        {task.dueDate && (
   175→                          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-0.5">
   176→                            Due today
   177→                          </div>
   178→                        )}
   179→                      </div>
   180→
   181→                      {/* Quick Actions (show on hover) */}
   182→                      <button
   183→                        onClick={() => navigate('/tasks')}
   184→                        className="flex-shrink-0 opacity-0 group-hover:opacity-100 text-xs text-accent-blue hover:underline transition-opacity"
   185→                      >
   186→                        View
   187→                      </button>
   188→                    </div>
   189→                  ))}
   190→                </div>
   191→              </div>
   192→            )}
   193→
   194→            {/* Completed Tasks (Collapsible) */}
   195→            {completedTasks.length > 0 && (
   196→              <div>
   197→                <button
   198→                  onClick={() => setShowCompleted(!showCompleted)}
   199→                  className="w-full text-left flex items-center gap-2 text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary uppercase tracking-wide mb-2 hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
   200→                >
   201→                  <span className={`transition-transform ${showCompleted ? 'rotate-90' : ''}`}>▶</span>
   202→                  Completed ({completedTasks.length})
   203→                </button>
   204→                {showCompleted && (
   205→                  <div className="space-y-1.5">
   206→                    {completedTasks.map((task) => (
   207→                      <div
   208→                        key={task.id}
   209→                        className="flex items-start gap-2 p-2 rounded opacity-60"
   210→                      >
   211→                        <div className="flex-shrink-0 mt-0.5 w-4 h-4 rounded border-2 border-status-success bg-status-success text-white flex items-center justify-center">
   212→                          <svg className="w-3 h-3" viewBox="0 0 12 12" fill="none">
   213→                            <path d="M2 6L5 9L10 3" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
   214→                          </svg>
   215→                        </div>
   216→                        <span className="flex-1 text-sm text-text-light-secondary dark:text-text-dark-secondary line-through">
   217→                          {task.title}
   218→                        </span>
   219→                      </div>
   220→                    ))}
   221→                  </div>
   222→                )}
   223→              </div>
   224→            )}
   225→
   226→            {/* Events Section */}
   227→            {todayEvents.length > 0 && (
   228→              <div>
   229→                <h3 className="text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary uppercase tracking-wide mb-2">
   230→                  Events
   231→                </h3>
   232→                <div className="space-y-1.5">
   233→                  {todayEvents.map((event) => (
   234→                    <button
   235→                      key={event.id}
   236→                      onClick={() => navigate('/schedule')}
   237→                      className="w-full text-left p-2 rounded hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-all duration-standard ease-smooth"
   238→                    >
   239→                      <div className="flex items-start gap-3">
   240→                        {event.startTime && (
   241→                          <div className="flex-shrink-0 w-14 text-xs font-medium text-accent-magenta">
   242→                            {event.startTime}
   243→                          </div>
   244→                        )}
   245→                        <div className="flex-1 min-w-0">
   246→                          <div className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
   247→                            {event.title}
   248→                          </div>
   249→                          {event.description && (
   250→                            <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-0.5 truncate">
   251→                              {event.description}
   252→                            </div>
   253→                          )}
   254→                        </div>
   255→                      </div>
   256→                    </button>
   257→                  ))}
   258→                </div>
   259→              </div>
   260→            )}
   261→          </div>
   262→        ) : (
   263→          <div className="flex-1 flex flex-col items-center justify-center text-center py-8">
   264→            <div className="text-5xl mb-3">🎉</div>
   265→            <p className="text-lg font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   266→              You're all clear!
   267→            </p>
   268→            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
   269→              No tasks or events for today
   270→            </p>
   271→          </div>
   272→        )}
   273→
   274→        {/* Action Buttons */}
   275→        <div className="grid grid-cols-2 gap-2 mt-auto pt-3 border-t border-border-light dark:border-border-dark">
